import React, { useState, useContext } from 'react';
import { AppContext } from '../App';
import { Colaborador } from '../types';

const Colaboradores: React.FC = () => {
  const { colaboradores, setColaboradores } = useContext(AppContext);
  const [searchTerm, setSearchTerm] = useState('');
  const [filter, setFilter] = useState<'All' | 'Ativo' | 'Afastado'>('All');
  
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);
  
  const [formData, setFormData] = useState<Partial<Colaborador>>({
    nome: '',
    numeroColaborador: '',
    nif: '',
    inss: '',
    cargo: '',
    tipoContrato: 'Contrato por Tempo Indeterminado',
    salarioBase: 0,
    status: 'Ativo',
    email: '',
    iban: '',
    dataAdmissao: new Date().toISOString().split('T')[0]
  });


  const filteredColaboradores = colaboradores.filter(c => {
    const matchesSearch = c.nome.toLowerCase().includes(searchTerm.toLowerCase()) || c.nif.includes(searchTerm) || c.cargo.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesFilter = filter === 'All' ? true : c.status === filter;
    return matchesSearch && matchesFilter;
  });

  const handleOpenModal = (colab?: Colaborador) => {
    if (colab) {
      setEditingId(colab.id);
      setFormData(colab);
    } else {
      setEditingId(null);
      setFormData({
        nome: '', numeroColaborador: '', nif: '', inss: '', cargo: '', tipoContrato: 'Efectivo', salarioBase: 0, status: 'Ativo', email: '', dataAdmissao: ''
      });
    }
    setIsModalOpen(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    
    const dataToSave = { ...formData };
    
    if (!editingId) {
      // Auto-generate numeroColaborador: [Ano][CargoAbrev][Seq]
      const year = dataToSave.dataAdmissao ? new Date(dataToSave.dataAdmissao).getFullYear() : new Date().getFullYear();
      const cargoAbrev = (dataToSave.cargo || 'FUNC').substring(0, 3).toUpperCase();
      const sequence = colaboradores.length + 1;
      dataToSave.numeroColaborador = `${year}${cargoAbrev}${sequence}`;
      
      const newColab = { ...dataToSave, id: Date.now() } as Colaborador;
      setColaboradores([...colaboradores, newColab]);
    } else {
      setColaboradores(colaboradores.map(c => c.id === editingId ? { ...c, ...dataToSave } as Colaborador : c));
    }
    setIsModalOpen(false);
  };


  const handleDelete = (id: number) => {
    if (window.confirm("Pretende mesmo eliminar este colaborador?")) {
      setColaboradores(colaboradores.filter(c => c.id !== id));
    }
  };

  return (
    <div className="p-8">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-8">
        <div className="flex flex-col gap-1">
          <h1 className="text-3xl font-black tracking-tight">Colaboradores</h1>
          <p className="text-slate-500 dark:text-slate-400">Gerencie informações, contratos e status da sua equipe.</p>
        </div>
        <button onClick={() => handleOpenModal()} className="flex items-center justify-center gap-2 rounded-lg h-11 px-6 bg-primary text-white text-sm font-bold hover:bg-primary/90 transition-all shadow-lg shadow-primary/20">
          <span className="material-symbols-outlined text-[20px]">person_add</span>
          Adicionar Novo Colaborador
        </button>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 p-4 mb-6">
        <div className="flex flex-col lg:flex-row gap-4 items-center justify-between">
          <div className="flex flex-1 w-full max-w-md items-center gap-3">
            <div className="relative w-full">
              <span className="material-symbols-outlined absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-[20px]">search</span>
              <input 
                className="w-full pl-10 pr-4 py-2.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-primary focus:border-primary outline-none text-sm transition-all" 
                placeholder="Pesquisar por nome, NIF ou cargo..." 
                type="text"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>
          <div className="flex flex-wrap items-center gap-2">
            <button onClick={() => setFilter('All')} className={`flex h-10 items-center justify-center gap-2 rounded-lg px-4 text-sm font-semibold border ${filter === 'All' ? 'bg-primary/10 text-primary border-primary/20' : 'bg-slate-50 text-slate-600 border-slate-200'} transition-colors`}>
              <span>Todos</span>
              <span className={`${filter === 'All' ? 'bg-primary' : 'bg-slate-400'} text-white text-[10px] px-1.5 py-0.5 rounded-full`}>{colaboradores.length}</span>
            </button>
            <button onClick={() => setFilter('Ativo')} className={`flex h-10 items-center justify-center gap-2 rounded-lg px-4 text-sm font-semibold border ${filter === 'Ativo' ? 'bg-emerald-100 text-emerald-700 border-emerald-200' : 'bg-slate-50 text-slate-600 border-slate-200'} transition-colors`}>
              <span className="material-symbols-outlined text-[18px]">check_circle</span>
              <span>Ativos</span>
              <span className="bg-emerald-500 text-white text-[10px] px-1.5 py-0.5 rounded-full">{colaboradores.filter(c => c.status === 'Ativo').length}</span>
            </button>
            <button onClick={() => setFilter('Afastado')} className={`flex h-10 items-center justify-center gap-2 rounded-lg px-4 text-sm font-semibold border ${filter === 'Afastado' ? 'bg-amber-100 text-amber-700 border-amber-200' : 'bg-slate-50 text-slate-600 border-slate-200'} transition-colors`}>
              <span className="material-symbols-outlined text-[18px]">pause_circle</span>
              <span>Afastados</span>
              <span className="bg-amber-500 text-white text-[10px] px-1.5 py-0.5 rounded-full">{colaboradores.filter(c => c.status === 'Afastado').length}</span>
            </button>
          </div>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Colaborador</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Nº e NIF/BI</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Cargo</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Salário</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase text-center">Status</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {filteredColaboradores.map((c) => (
                <tr key={c.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/30 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="size-9 rounded-full bg-primary/10 text-primary flex items-center justify-center font-bold text-xs uppercase">
                        {c.nome.substring(0, 2)}
                      </div>
                      <div>
                        <span className="text-sm font-semibold text-slate-900 dark:text-slate-100">{c.nome}</span>
                        <span className="text-xs text-slate-500 block">{c.email}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600">
                    <div><span className="font-semibold text-xs">ID:</span> {c.numeroColaborador || '-'}</div>
                    <div className="text-xs">{c.nif}</div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="px-2.5 py-1 rounded-full text-xs font-medium bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300">{c.cargo}</span>
                  </td>
                  <td className="px-6 py-4 text-sm font-medium">{Number(c.salarioBase).toLocaleString()} Kz</td>
                  <td className="px-6 py-4 text-center">
                    <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold ${
                      c.status === 'Ativo' ? 'bg-emerald-100 text-emerald-700' :
                      c.status === 'Afastado' ? 'bg-amber-100 text-amber-700' :
                      'bg-slate-100 text-slate-700'
                    }`}>
                      <span className={`size-1.5 rounded-full ${
                        c.status === 'Ativo' ? 'bg-emerald-500' :
                        c.status === 'Afastado' ? 'bg-amber-500' : 'bg-slate-400'
                      }`}></span>
                      {c.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end gap-2">
			<button onClick={() => handleOpenModal(c)} className="text-slate-400 hover:text-primary transition-colors p-2 rounded-lg hover:bg-slate-100">
                      <span className="material-symbols-outlined text-[18px]">edit</span>
                    </button>
                    	<button onClick={() => handleDelete(c.id)} className="text-slate-400 hover:text-red-500 transition-colors p-2 rounded-lg hover:bg-slate-100">
                      <span className="material-symbols-outlined text-[18px]">delete</span>
                    </button>
                    </div>
                  </td>
                </tr>
              ))}
              {filteredColaboradores.length === 0 && (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-slate-500">Nenhum colaborador encontrado com os filtros selecionados.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal Adicionar/Editar */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="px-6 py-4 border-b border-slate-200 dark:border-slate-800 flex items-center justify-between bg-slate-50 dark:bg-slate-800/50">
              <h3 className="text-lg font-bold text-slate-800 dark:text-white flex items-center gap-2">
                <span className="material-symbols-outlined text-primary">{editingId ? 'edit' : 'person_add'}</span>
                {editingId ? 'Editar Colaborador' : 'Adicionar Colaborador'}
              </h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600 transition-colors">
                <span className="material-symbols-outlined">close</span>
              </button>
            </div>
            
            <form onSubmit={handleSave} className="flex-1 overflow-y-auto p-6 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">Nome Completo *</label>
                  <input required value={formData.nome} onChange={e => setFormData({...formData, nome: e.target.value})} className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">Endereço de Email *</label>
                  <input required type="email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">IBAN *</label>
                  <input required placeholder="AO06 ...." value={formData.iban || ''} onChange={e => setFormData({...formData, iban: e.target.value})} className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary font-mono" />
                </div>

                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">NIF ou BI *</label>
                  <input required value={formData.nif} onChange={e => setFormData({...formData, nif: e.target.value})} className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">Nº INSS (Opcional)</label>
                  <input value={formData.inss || ''} onChange={e => setFormData({...formData, inss: e.target.value})} className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">Cargo</label>
                  <input required value={formData.cargo} onChange={e => setFormData({...formData, cargo: e.target.value})} className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">Salário Base (Kz) *</label>
                  <div className="relative">
                    <input 
                      required 
                      type="text" 
                      value={formData.salarioBase ? formData.salarioBase.toLocaleString('pt-AO') : ''} 
                      onChange={e => {
                        const val = e.target.value.replace(/\D/g, '');
                        setFormData({...formData, salarioBase: Number(val)});
                      }} 
                      onBlur={e => {
                        if (formData.salarioBase) {
                          e.target.value = formData.salarioBase.toLocaleString('pt-AO', { minimumFractionDigits: 2 }) + ' Kz';
                        }
                      }}
                      className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary font-bold text-primary" 
                      placeholder="0,00 Kz"
                    />
                  </div>
                </div>

                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">Data Início</label>
                  <input type="date" value={formData.dataAdmissao || ''} onChange={e => setFormData({...formData, dataAdmissao: e.target.value})} className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">Tipo de Contrato</label>
                  <select value={formData.tipoContrato} onChange={e => setFormData({...formData, tipoContrato: e.target.value as any})} className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary">
                    <option value="Contrato por Tempo Indeterminado">Tempo Indeterminado</option>
                    <option value="Contrato a Termo Certo">Termo Certo</option>
                    <option value="Contrato a Termo Incerto">Termo Incerto</option>
                    <option value="Contrato de Trabalho Eventual">Trabalho Eventual</option>
                  </select>

                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">Status</label>
                  <select value={formData.status} onChange={e => setFormData({...formData, status: e.target.value as any})} className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary">
                    <option value="Ativo">Ativo</option>
                    <option value="Afastado">Afastado</option>
                    <option value="Desligado">Desligado</option>
                  </select>
                </div>
              </div>

              <div className="pt-6 border-t border-slate-200 flex justify-end gap-3 mt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="px-5 py-2 font-bold text-slate-500 hover:text-slate-700 transition-colors">Cancelar</button>
                <button type="submit" className="px-5 py-2 rounded-lg bg-primary text-white font-bold hover:bg-primary/90 flex items-center gap-2">
                  <span className="material-symbols-outlined text-[18px]">save</span>
                  Salvar Dados
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Colaboradores;
